class Solution:
    def minSwaps(self, s: str) -> int:
        balance = 0
        swaps = 0
        for bracket in s:
            if bracket == '[':
                balance += 1
            else:
                balance -= 1
            if balance < 0:
                swaps += 1
                balance += 2
        return swaps
```
